#include <iostream>
#include <vector>

using namespace std;

void doubleInPlace(vector<int> &numbers)
{
    for (int i = 0; i < numbers.size(); i++)
    {
        numbers[i] = numbers[i] * 2; // modify directly, no new array
    }
}

int main()
{
    vector<int> numbers = {1, 2, 3};

    doubleInPlace(numbers);

    for (int n : numbers)
    {
        cout << n << " ";
    }

    return 0;
}

