int findMax(vector<int> &numbers)
{
    int maxVal = numbers[0];
    for (int i = 1; i < numbers.size(); i++)
    {
        if (numbers[i] > maxVal)
        {
            maxVal = numbers[i];
        }
    }
    return maxVal;
}

int main()
{
    vector<int> numbers = {4, 9, 2, 7};

    cout << findMax(numbers) << endl;

    return 0;
}

