#include <iostream>
#include <vector>

using namespace std;

vector<int> runningSum(vector<int> &nums)
{
    vector<int> result(nums.size());

    for (int i = 0; i < nums.size(); i++)
    {
        int sum = 0;
        for (int j = 0; j <= i; j++)
        {
            sum += nums[j];
        }
        result[i] = sum;
    }

    return result;
}

int main()
{
    vector<int> nums = {1, 2, 3, 4};
    vector<int> result = runningSum(nums);

    for (int n : result) cout << n << " ";

    return 0;
}

