using namespace std;

vector<int> runningSum(vector<int> &nums)
{
    for (int i = 1; i < nums.size(); i++)
    {
        nums[i] += nums[i - 1]; // nums[i-1] is already the running sum up to i-1
    }

    return nums;
}

