#include <iostream>
#include <vector>

using namespace std;

int maximumWealth(vector<vector<int>> &accounts)
{
    vector<int> wealths;

    for (auto &row : accounts)
    {
        int sum = 0;
        for (int coins : row) sum += coins;
        wealths.push_back(sum);
    }

    int best = wealths[0];
    for (int w : wealths)
    {
        if (w > best) best = w;
    }

    return best;
}

int main()
{
    vector<vector<int>> accounts = {{1, 2, 3}, {3, 2, 1}};

    cout << maximumWealth(accounts) << endl;

    return 0;
}

